package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Whitelist;

import static org.junit.Assert.*;

public class StepDefs {
    private Document document;
    private Parser xmlParser;

    @Given("an XML parser configured with HTML default settings")
    public void an_XML_parser_configured_with_HTML_default_settings() {
        // Use XML parser with HTML settings (this should represent the bug scenario)
        xmlParser = Parser.xmlParser();
    }

    @When("I parse the input {string}")
    public void i_parse_the_input(String input) {
        try {
            document = Jsoup.parse(input, "", xmlParser);
        } catch (Exception e) {
            // Handle exception if needed for testing
            throw new RuntimeException(e);
        }
    }

    @Then("the resulting document should match {string}")
    public void the_resulting_document_should_match(String expected) {
        String actual = document.toString().trim();
        String normalizedExpected = expected.replaceAll("\\s+", " ").trim();
        String normalizedActual = actual.replaceAll("\\s+", " ").trim();
        assertTrue("Document does not match expected output. Expected: " + normalizedExpected + ", Actual: " + normalizedActual, 
                   actual.contains(normalizedExpected) || normalizedActual.equals(normalizedExpected));
    }

    @Then("the {string} element should be a sibling of the {string} element")
    public void the_element_should_be_a_sibling_of_the_element(String element1, String element2) {
        // Get the parent of the first element
        Element firstEl = document.selectFirst(element1);
        assertNotNull("Element " + element1 + " not found", firstEl);

        Element secondEl = document.selectFirst(element2);
        assertNotNull("Element " + element2 + " not found", secondEl);

        // Check that both elements have the same parent (making them siblings)
        assertEquals("Elements are not siblings - different parents", 
                     firstEl.parent(), secondEl.parent());
    }
}
